import React from 'react';
import styled from "styled-components";
import RainyDay from "rainyday.js/dist/rainyday.min"

const Background = styled.div`
  height: 100vh;
  background-position: center;
  background-repeat: no-repeat;
  background-size: cover;
  //background-image: url(https://i.imgur.com/fHyEMsl.jpg);
  background-color: black;
  overflow: hidden;
  transform-origin: bottom;
`;

class Rain extends React.Component {
    ref = React.createRef();

    componentDidMount() {
        const image = this.ref.current;
        const engine = new RainyDay({
            image,
            onInitialized: () => {
                engine.rain([[1, 2, 8000]]);
                engine.rain([[3, 3, 0.88], [5, 5, 0.9], [6, 2, 1]], 100);
            }
        });
    }

    render() {
        return <Background ref={this.ref} />;
    }
}

export const Home = ()=> {
    return (
        <Background>
            Hello
        </Background>

    )
}
